/// <summary>
/// <c>ETGSPAINInventTransOperationDP</c> is the Data Provider class
/// for the Transactions by Operation Report in the ETGSPAIN model.
/// </summary>
[
    SRSReportParameterAttribute(classStr(ETGSPAINInventTransOperationContract)),
    SRSReportQueryAttribute(queryStr(ETGSPAINInventTransOperationQuery))
]
class ETGSPAINInventTransOperationDP extends SrsReportDataProviderPreProcessTempDB
{
    protected ETGSPAINInventTransOperationReportTmp  ETGSPAINInventTransOperationReportTmp;
    protected ParmId                            parmId;
    protected int                               minus;
    protected InventDimParm                     inventDimParm;
    protected FromDate                          fromDate;
    protected ToDate                            toDate;
    protected NoYes                             showItem;
    protected InventDimItemTmp                  inventDimItemTmpInventTrans;

}

Method.Source:
/// <summary>
/// Populates the temporary table <c>ETGSPAINInventTransOperationReportTmp</c> that will appear in the report.
/// </summary>
/// <returns>The temporary table <c>ETGSPAINInventTransOperationReportTmp</c>.</returns>
[
    SRSReportDataSetAttribute('ETGSPAINInventTransOperationReportTmp')
]
public ETGSPAINInventTransOperationReportTmp getETGSPAINInventTransOperationReportTmp()
{
    select * from ETGSPAINInventTransOperationReportTmp;
    return ETGSPAINInventTransOperationReportTmp;
}

/// <summary>
/// Initializes the inventory dimension parameters to generate the report.
/// </summary>
/// <param name="_contract">The contract class.</param>
protected void initInventDimParm(ETGSPAINInventTransOperationContract _contract)
{        
    InventDimViewContract inventDimViewContract = _contract.parmInventDimViewContract();

    inventDimParm.data(inventDimViewContract.parmInventDimParm());
}

/// <summary>
/// Processes the report by inserting data into the temporary table.
/// </summary>
public void processReport()
{
    ETGSPAINInventTransOperationContract contract = this.parmDataContract();

    super();        

    this.initInventDimParm(contract);

    parmId   = NumberSeq::newGetNum(CompanyInfo::numRefParmId()).num();
    minus    = -1;
    fromDate = contract.parmFromDate();
    toDate   = contract.parmToDate() ? contract.parmToDate() : dateMax();
    showItem = contract.parmShowItem();

    // Solo generamos los cálculos si está activada el Número de Operación (Número de Lote)
    if (inventDimParm.InventBatchIdFlag)
    {
        this.deleteTransactions();        

        this.calcData();

        this.constructETGSPAINInventTransOperationReportTmp();
    }
}

/// <summary>
/// Adds the connection to the table.
/// </summary>
/// <param name="_common">The table.</param>
private void setUserConnection(Common _common)
{
    UserConnection con = this.parmUserConnection();

    if (con)
    {
        _common.setConnection(con);
    }
}

/// <summary>
/// Deletes previously stored transactions for the same parmId.
/// </summary>
protected void deleteTransactions()
{
    ETGSPAINInventTransOperation       ETGSPAINInventTransOperation;

    if (this.parmUserConnection())
    {
        ETGSPAINInventTransOperation.setConnection(this.parmUserConnection());
    }

    if (parmId)
    {
        delete_from ETGSPAINInventTransOperation
              where ETGSPAINInventTransOperation.ParmId == parmId;
    }
}

/// <summary>
/// Calculates quantities for the selected records.
/// </summary>
private void calcData()
{
    InventTrans     inventTrans;

    if (this.parmUserConnection())
    {
        inventTrans.setConnection(this.parmUserConnection());
    }

    QueryBuildDataSource qbds = this.parmQuery().dataSourceTable(tableNum(InventTrans));

    qbds.addRange(fieldNum(InventTrans, DateStatus)).value(queryRange(fromDate, toDate));        

    QueryRun queryRun = new QueryRun(this.parmQuery());

    while (queryRun.next())
    {
        inventTrans = queryRun.get(tableNum(InventTrans));

        this.calcUnsoldByInventDimItem(inventTrans.ItemId, inventTrans.inventDimId);
        this.calcPhysicalByInventDimItem(inventTrans.ItemId, inventTrans.inventDimId);
        this.calcFinancialByInventDimItem(inventTrans.ItemId, inventTrans.inventDimId);
    }
}

