/// <summary>
/// Calculates the physical quantity.
/// </summary>
/// <param name="_itemId">Item ID.</param>
/// <param name="_inventDimId">Inventory dimensions.</param>
private void calcPhysicalByInventDimItem(ItemId _itemId, InventDimId _inventDimId)
{
    ETGSPAINInventTransOperation   ETGSPAINInventTransOperation;
    InventTrans               inventTrans;
    InventDim                 inventDim;
    InventLocation            inventLocation;             

    if (this.parmUserConnection())
    {
        ETGSPAINInventTransOperation.setConnection(this.parmUserConnection());
        inventTrans.setConnection(this.parmUserConnection());
        inventDim.setConnection(this.parmUserConnection());
        inventLocation.setConnection(this.parmUserConnection());
    }

    // Compras: Registrado + Recibido + Comprado += Qty
    insert_recordset ETGSPAINInventTransOperation (ItemId, InventDimId, QtyPhysical, #InventDimGroupAllFields, ParmId)
        select       ItemId, InventDimId, sum(Qty)
            from     inventTrans
            group by ItemId, InventDimId
            where    inventTrans.DatePhysical  >= fromDate
            &&       inventTrans.DatePhysical  <= toDate
            &&      (inventTrans.StatusReceipt == StatusReceipt::Received
            ||       inventTrans.StatusReceipt == StatusReceipt::Registered
            ||       inventTrans.StatusReceipt == StatusReceipt::Purchased)
            &&       inventTrans.StatusIssue   == StatusIssue::None
            &&       inventTrans.ItemId        == _itemId
            &&       inventTrans.InventDimId   == _inventDimId
        join         #InventDimGroupAllFields, parmId
            from     inventDim
            group by #InventDimGroupAllFields
            where    inventDim.inventDimId == inventTrans.inventDimId
        exists join  inventLocation
            where    inventLocation.InventLocationId == inventDim.InventLocationId
            &&       inventLocation.ETGSPAINIsPrevInvoice == NoYes::No;

    // Ventas: Seleccionado + Deducido -= Qty
    insert_recordset ETGSPAINInventTransOperation (ItemId, InventDimId, QtyPhysical, #InventDimGroupAllFields, ParmId, Sign)
        select       ItemId, InventDimId, sum(Qty)
            from     inventTrans
            group by ItemId, InventDimId
            where    inventTrans.DatePhysical  >= fromDate
            &&       inventTrans.DatePhysical  <= toDate
            &&       inventTrans.StatusReceipt == StatusReceipt::None
            &&      (inventTrans.StatusIssue   == StatusIssue::Picked
            ||       inventTrans.StatusIssue   == StatusIssue::Deducted
            ||       inventTrans.StatusIssue   == StatusIssue::Sold)
            &&       inventTrans.ItemId        == _itemId
            &&       inventTrans.InventDimId   == _inventDimId
        join         #InventDimGroupAllFields, parmId, minus
            from     inventDim
            group by #InventDimGroupAllFields
            where    inventDim.inventDimId == inventTrans.inventDimId
        exists join  inventLocation
            where    inventLocation.InventLocationId == inventDim.InventLocationId
            &&       inventLocation.ETGSPAINIsPrevInvoice == NoYes::No;
}

/// <summary>
/// Calculates the financial quantity.
/// </summary>
/// <param name="_itemId">Item ID.</param>
/// <param name="_inventDimId">Inventory dimensions.</param>
private void calcFinancialByInventDimItem(ItemId _itemId, InventDimId _inventDimId)
{
    ETGSPAINInventTransOperation   ETGSPAINInventTransOperation;
    InventTrans               inventTrans;
    InventDim                 inventDim;

    if (this.parmUserConnection())
    {
        ETGSPAINInventTransOperation.setConnection(this.parmUserConnection());
        inventTrans.setConnection(this.parmUserConnection());
        inventDim.setConnection(this.parmUserConnection());
    }

    // Comprado += Qty
    insert_recordset ETGSPAINInventTransOperation (ItemId, InventDimId, QtyFinancial, #InventDimGroupAllFields, ParmId)
        select       ItemId, InventDimId, sum(Qty)
            from     inventTrans
            group by ItemId, InventDimId
            where    inventTrans.DateFinancial >= fromDate
            &&       inventTrans.DateFinancial <= toDate
            &&       inventTrans.StatusReceipt == StatusReceipt::Purchased
            &&       inventTrans.StatusIssue   == StatusIssue::None
            &&       inventTrans.ItemId        == _itemId
            &&       inventTrans.InventDimId   == _inventDimId
        join         #InventDimGroupAllFields, parmId
            from     inventDim
            group by #InventDimGroupAllFields
            where    inventDim.inventDimId == inventTrans.inventDimId;

    // Vendido -= Qty        
    insert_recordset ETGSPAINInventTransOperation (ItemId, InventDimId, QtyFinancial, #InventDimGroupAllFields, ParmId, Sign)
        select       ItemId, InventDimId, sum(Qty)
            from     inventTrans
            group by ItemId, InventDimId
            where    inventTrans.DateFinancial >= fromDate
            &&       inventTrans.DateFinancial <= toDate
            &&       inventTrans.StatusReceipt == StatusReceipt::None
            &&       inventTrans.StatusIssue   == StatusIssue::Sold
            &&       inventTrans.ItemId        == _itemId
            &&       inventTrans.InventDimId   == _inventDimId
        join         #InventDimGroupAllFields, parmId, minus
            from     inventDim
            group by #InventDimGroupAllFields
            where    inventDim.inventDimId == inventTrans.inventDimId;
}

/// <summary>
/// Populates the temporary table <c>ETGSPAINInventTransOperationReportTmp</c> with the calculated data.
/// </summary>
private void constructETGSPAINInventTransOperationReportTmp()
{
    ETGSPAINInventTransOperation       ETGSPAINInventTransOperation;
    boolean                       showCustVendName  = false;
    Counter                       countDimensionsActivated = 0;

    if (this.parmUserConnection())
    {
        ETGSPAINInventTransOperation.setConnection(this.parmUserConnection());
    }

    Query targetQuery = new Query();

    QueryBuildDataSource qbds = targetQuery.addDataSource(tableNum(ETGSPAINInventTransOperation));

    qbds.addRange(fieldNum(ETGSPAINInventTransOperation, ParmId)).value(queryValue(parmId));


    Enumerator inventDimFieldsEnumerator = InventDim::dimEnabledFieldList().getEnumerator();
    while (inventDimFieldsEnumerator.moveNext())
    {
        FieldId inventDimFieldId = inventDimFieldsEnumerator.current();
        FieldId inventDimParmFieldId = InventDim::dim2dimParm(inventDimFieldId);

        if (inventDimParm.(inventDimParmFieldId))
        {
            FieldId inventTransOperationFieldId = ETGSPAINInventTransOperation::getInventTransOperationFieldIdFromInventDimFieldId(inventDimFieldId);
            qbds.addSelectionField(inventTransOperationFieldId);
            qbds.addGroupByField(inventTransOperationFieldId);

            countDimensionsActivated++;
        }
    }

    // Comprobamos si debemos mostrar la información de Proveedor/Cliente
    // Solamente si hay activadas más dimensiones a parte de la Operación.
    if (countDimensionsActivated > 1)
    {
        showCustVendName = true;
    }

    if (showItem)
    {
        qbds.addSelectionField(fieldNum(ETGSPAINInventTransOperation, ItemId));
        qbds.addGroupByField(fieldNum(ETGSPAINInventTransOperation, ItemId));
    }

    qbds.addSelectionField(fieldNum(ETGSPAINInventTransOperation, QtyApplication), SelectionField::Sum);
    qbds.addSelectionField(fieldNum(ETGSPAINInventTransOperation, QtyFinancial), SelectionField::Sum);
    qbds.addSelectionField(fieldNum(ETGSPAINInventTransOperation, QtyPhysical), SelectionField::Sum);

    QueryRun queryRun = new QueryRun(targetQuery);
    queryRun.setCursor(ETGSPAINInventTransOperation);

    while (queryRun.next())
    {
        ETGSPAINInventTransOperation = queryRun.get(tableNum(ETGSPAINInventTransOperation));

        if (ETGSPAINInventTransOperation.QtyApplication   != 0 ||
            ETGSPAINInventTransOperation.QtyFinancial     != 0 ||
            ETGSPAINInventTransOperation.QtyPhysical      != 0 )
        {
            InventDim inventDim;

            inventDim.ETGSPAINinitFromETGSPAINInventTransOperation(ETGSPAINInventTransOperation);

            ETGSPAINInventTransOperationReportTmp.clear();

            ETGSPAINInventTransOperationReportTmp.initFromETGSPAINInventTransOperation(ETGSPAINInventTransOperation, inventDim);

            ETGSPAINInventTransOperationReportTmp.ShowCustVendName = showCustVendName;                

            if (showCustVendName)
            {
                if (inventDimParm.InventSerialIdFlag || inventDimParm.InventDimension1Flag)
                {
                    ETGSPAINInventTransOperationReportTmp.CustVendName = this.getCustVendNameFromDim(inventDim);
                }
                else
                {
                    ETGSPAINInventTransOperationReportTmp.CustVendName = "@ETGSPAINLabels:Several";
                }
            }

            if (inventDimParm.InventDimension1Flag)
            {
                ETGSPAINInventTransOperationReportTmp.ETGSPAINPlateDueDate = this.getPurchVendETGSPAINPlateDueDateFromDim(inventDim);
            }

            ETGSPAINInventTransOperationReportTmp.insert();
        }
    }
}

/// <summary>
/// Retrieves the vendor/customer name through the inventory dimensions.
/// </summary>
/// <param name="_inventDim">Inventory dimensions.</param>
/// <returns>The vendor/customer name.</returns>
private CustVendName getCustVendNameFromDim(InventDim _inventDim)
{        
    // Revisamos si está activada y rellenada la dimensión "Aplicación"
    if (inventDimParm.InventDimension1Flag && _inventDim.InventDimension1)
    {
        PurchTable  purchTable;
        SalesTable  salesTable;

        purchTable = PurchTable::find(_inventDim.InventDimension1);

        if (!purchTable)
        {
            salesTable = SalesTable::find(_inventDim.InventDimension1);

            return salesTable.customerName();
        }
        else
        {
            return purchTable.vendorName();
        }
    }

    // Revisamos si está activada y rellenada la dimensión "Contrato"
    if (inventDimParm.InventSerialIdFlag && _inventDim.inventSerialId)
    {
        PurchAgreementHeader    purchAgreementHeader;            
        SalesAgreementHeader    salesAgreementHeader;
        AgreementHeader         agreementHeader;
        AgreementLine           agreementLine;
        InventDim               inventDim;

        select firstonly agreementHeader
            join         agreementLine
            where        agreementLine.Agreement == agreementHeader.RecId
            exists join  inventDim
            where        inventDim.inventDimId == agreementLine.InventDimId
            &&           inventDim.inventSerialId == _inventDim.inventSerialId;

        if (agreementHeader)
        {
            purchAgreementHeader = PurchAgreementHeader::find(agreementHeader.RecId);

            if (!purchAgreementHeader)
            {
                salesAgreementHeader = SalesAgreementHeader::find(agreementHeader.RecId);

                return salesAgreementHeader.custName();
            }
            else
            {
                return purchAgreementHeader.vendName();
            }
        }

    }

    return '';
}

/// <summary>
/// Retrieves the plate due date of the purchase/sales order through the inventory dimensions.
/// </summary>
/// <param name="_inventDim">Inventory dimensions.</param>
/// <returns>The plate due date of the purchase/sales order.</returns>
private TransDate getPurchVendETGSPAINPlateDueDateFromDim(InventDim _inventDim)
{
    // Revisamos si está activada y rellenada la dimensión "Aplicación"
    if (inventDimParm.InventDimension1Flag && _inventDim.InventDimension1)
    {
        PurchTable  purchTable;
        SalesTable  salesTable;

        purchTable = PurchTable::find(_inventDim.InventDimension1);

        if (!purchTable)
        {
            salesTable = SalesTable::find(_inventDim.InventDimension1);

            return salesTable.ETGSPAINPlateDueDate;
        }
        else
        {
            return purchTable.ETGSPAINPlateDueDate;
        }
    }

    return dateNull();
}
